import{_ as d,o as a,c as o,a0 as l}from"./chunks/framework.C9qqnGT6.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog.md","filePath":"en/changelog.md"}'),i={name:"en/changelog.md"};function c(r,e,t,h,n,u){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>このファイルは <code>git tag</code>・コミット履歴・バージョン更新コミットをもとに再構成した変更履歴です。</p><ul><li><code>v1.0.0</code> 〜 <code>v1.2.0</code> はリポジトリ内のタグを基準に整理しています。</li><li><code>1.2.1</code> は <code>src/validkit/__init__.py</code> の <code>__version__ = &quot;1.2.1&quot;</code> と 2026-03-07 の関連コミットを基準に整理しています（現時点で対応タグは未確認）。</li><li>変更点は読みやすさのために <code>Added</code> / <code>Changed</code> / <code>Fixed</code> に要約しています。</li></ul><h2 id="_1-3-3dev1-2026-07-05" tabindex="-1">[1.3.3dev1] - 2026-07-05 <a class="header-anchor" href="#_1-3-3dev1-2026-07-05" aria-label="Permalink to &quot;[1.3.3dev1] - 2026-07-05&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>クラス記法スキーマの変換結果をキャッシュし、同じクラススキーマを繰り返し検証する通常パスのオーバーヘッドを削減しました。</li><li>コンパイル済みスキーマのPython経路では、戻り値と入力値の aliasing を避ける互換性テストを追加しました。</li><li>Pydantic との比較ベンチマークを踏まえ、ホットパス最適化と将来的なネイティブ実装検討に向けた計画を整理しました。</li><li>実験的な Rust/PyO3 ネイティブ検証コア <code>validkit-py-core</code> を追加し、対応可能な pure dict/list/str/int/float/bool スキーマでは <code>compile(...).validate(...)</code> が起動時判定済みのネイティブ経路を使えるようにしました。</li><li>ネイティブ経路は性能を優先し、出力形状の変換が不要な成功ケースでは検証済みの入力オブジェクトをそのまま返すゼロコピー寄りの動作にしました。</li><li>ネイティブ拡張が無い環境、<code>VALIDKIT_DISABLE_NATIVE=1</code>、未対応機能、<code>partial</code> / <code>base</code> / <code>migrate</code> では従来のPython経路へ自動フォールバックするようにしました。</li><li>ネイティブコアで排他的な数値境界とリスト長制約を検証できるようにしました。</li><li>ベンチマークに <code>--native-mode auto|python|native|both</code> を追加し、ネイティブ有無にかかわらずPython経路とネイティブ経路を比較できるようにしました。</li><li><code>ValidationResult</code> に <code>has_errors</code> と <code>error_count</code> を追加し、<code>collect_errors=True</code> の詳細な <code>ErrorDetail</code> は <code>errors</code> アクセス時に遅延生成するようにしました。</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Rustブリッジで未対応の排他的数値境界とリスト長制約を誤ってネイティブ処理せず、Python互換の検証へ戻すようにしました。</li></ul><h2 id="_1-3-2-2026-07-04" tabindex="-1">[1.3.2] - 2026-07-04 <a class="header-anchor" href="#_1-3-2-2026-07-04" aria-label="Permalink to &quot;[1.3.2] - 2026-07-04&quot;">​</a></h2><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>コンパイル済みスキーマの通常検証パスを高速化し、不要なエラーリスト生成とキーワード引数呼び出しを避けるようにしました。</li><li>コンパイル時にクラススキーマの復元方法を判定し、dataclass / <code>NamedTuple</code> 変換時の実行時判定を削減しました。</li><li>dict スキーマの生成コードを最適化し、成功パスでの余分なフラグ分岐、辞書参照、トップレベル path 計算を減らしました。</li><li><code>base</code> が無い通常ケースで、欠損補完用の空 dict 生成を避けるようにしました。</li><li>コンパイル済みスキーマで通常検証用と <code>collect_errors=True</code> 用の生成関数を分け、実行モードごとの分岐を減らしました。</li><li>コンパイル済みスキーマの非収集パスで、内部呼び出しを位置引数ベースにして呼び出しオーバーヘッドを削減しました。</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>コンパイル済みの入れ子 dict スキーマで <code>base</code> の子要素が再帰先に渡らず、<code>partial=True</code> や <code>.when(...)</code> のスキップ時に既存値を補完できない問題を修正しました。</li></ul><h2 id="_1-3-1-2026-07-03" tabindex="-1">[1.3.1] - 2026-07-03 <a class="header-anchor" href="#_1-3-1-2026-07-03" aria-label="Permalink to &quot;[1.3.1] - 2026-07-03&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>v.list(...)</code> に <code>.min(length)</code> / <code>.max(length)</code> / <code>.length(length)</code> を追加し、要素数を検証できるようにしました。</li><li>数値バリデータの <code>.min()</code> / <code>.max()</code> に <code>exclusive=True</code>、<code>.range()</code> に <code>exclusive_min=True</code> / <code>exclusive_max=True</code> を追加しました。</li><li>dataclass と <code>NamedTuple</code> をクラススキーマとして渡した場合、検証済みのインスタンスを返すようにしました。</li><li><code>benchmarks/benchmark_validation.py</code> を追加し、通常の <code>validate()</code> と <code>compile(...).validate()</code> の速度を依存なしで比較できるようにしました。</li><li>ValidKit 用の VitePress ドキュメント生成スクリプトと日英ドキュメントを整備しました。</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>Schema.generate_sample()</code> がリストの最小要素数と数値の排他的境界を考慮して、有効なサンプルを生成するようになりました。</li><li>dataclass の <code>default_factory</code> を欠損値の補完に使用し、<code>init=False</code> フィールドは入力スキーマから除外するようにしました。</li><li>dataclass / <code>NamedTuple</code> の partial 検証は、必須コンストラクタ引数が不足し得るため従来どおり辞書を返します。</li><li>GitHub Actions の CI / Security / docs preview / deploy ワークフローを ValidKit 用に整理し、GitHub Pages の <code>validkit.disnana.com</code> 配置に合わせました。</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>排他的な上下限が同値で、有効値が存在しない数値範囲を定義時に拒否するようにしました。</li><li>新規コードに含まれていた末尾空白とスタイル上の問題を修正しました。</li><li>コンパイル済みスキーマで入れ子の <code>v.list(...)</code> / <code>v.dict(...)</code> を検証したとき、一時変数の衝突により結果が壊れる問題を修正しました。</li><li><code>env(..., decryptor=...)</code> を含むコンパイル済みスキーマが、復号失敗を <code>collect_errors=True</code> で扱うと生成コードの構文エラーになる問題を修正しました。</li><li>フォールバック検証される特殊バリデータで <code>.custom(...)</code> が二重実行される問題を修正しました。</li></ul><h2 id="_1-3-0dev2-2026-03-31" tabindex="-1">[1.3.0dev2] - 2026-03-31 <a class="header-anchor" href="#_1-3-0dev2-2026-03-31" aria-label="Permalink to &quot;[1.3.0dev2] - 2026-03-31&quot;">​</a></h2><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>.env(key, decryptor=None)</strong> 入力データが欠損している場合に、指定した環境変数から値を自動補完します。必要に応じて <code>decryptor</code> 引数に関数を渡すことで、取得した値を復号（または加工）してから検証できます。</li><li><strong>decryptor 引数の詳細</strong><code>decryptor</code> に渡す関数は <code>(value: str) -&gt; Any</code> のシグネチャを持つ必要があります。これにより、環境変数から取得した文字列を検証前に任意の型へ変換・復号することが可能です。</li></ul><h2 id="_1-3-0dev1-2026-03-31" tabindex="-1">[1.3.0dev1] - 2026-03-31 <a class="header-anchor" href="#_1-3-0dev1-2026-03-31" aria-label="Permalink to &quot;[1.3.0dev1] - 2026-03-31&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>すべてのバリデータで利用可能なセキュリティ・開発体験向上メソッドを追加しました。 <ul><li><code>.secret()</code>: バリデーションエラー時に元の入力値を例外メッセージからマスク (<code>***</code>) する機能を追加しました。</li><li><code>.env(key)</code>: 入力データが欠損している場合に、指定した環境変数（例: <code>os.environ[key]</code>）から値を自動補完する機能を追加しました。</li><li><code>.error_msg(msg)</code>: 検証エラー時のメッセージを、開発者が指定した独自のメッセージに上書きできる機能を追加しました。</li></ul></li><li>新しいバリデータクラスを追加しました。 <ul><li><code>v.url()</code>: URL フォーマットを検証します。チェインメソッドで特定のスキーム (<code>.schemes()</code>)、ドメイン (<code>.domains()</code>)、サブドメイン (<code>.subdomains()</code>)、パス (<code>.paths()</code>)、必須クエリパラメータ (<code>.query_keys()</code>) に制限可能です。</li><li><code>v.enum(enum_cls)</code>: Python 標準の <code>enum.Enum</code> とのシームレスな統合。<code>.coerce()</code> で文字列から自動的に Enum インスタンスへ変換します。</li></ul></li></ul><h2 id="_1-3-0dev0-2026-03-31" tabindex="-1">[1.3.0dev0] - 2026-03-31 <a class="header-anchor" href="#_1-3-0dev0-2026-03-31" aria-label="Permalink to &quot;[1.3.0dev0] - 2026-03-31&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>ライセンス認証システム向けの高度なバリデータ群を追加しました。</li><li><code>v.datetime()</code>: 日時 (<code>datetime.datetime</code> / <code>datetime.date</code>) の検証、および <code>.after_now()</code> / <code>.before_now()</code> による期限チェックに対応しました。</li><li><code>v.uuid()</code>: UUID 形式の検証、および <code>.version(n)</code> によるバージョン制限をサポートしました。</li><li><code>v.mac()</code>: MAC アドレス形式 (<code>00:11:22...</code>) の検証に対応しました。</li><li><code>v.sid()</code>: Windows Security Identifier (SID) 形式 (<code>S-1-5-21-...</code>) の検証に対応しました。</li><li><code>v.hwid()</code>: 汎用ハードウェア ID を検証するバリデータを追加しました。<code>.length(n)</code> や <code>.hex()</code> で制限可能です。</li><li><code>v.ip()</code>: IP アドレス (IPv4/IPv6) の検証、および <code>.v4_only()</code> / <code>.v6_only()</code> によるプロトコル特定に対応しました。</li><li><code>v.snowflake()</code>: Discord Snowflake ID の検証に対応しました。<code>.coerce()</code> で文字列から整数への自動変換をサポートします。</li><li><code>v.version()</code>: Semantic Versioning (SemVer) 形式を検証するバリデータを追加しました。</li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>v.datetime()</code> において、タイムゾーンを持つ日時（aware）と持たない日時（naive）を比較した際に <code>TypeError</code> が発生する問題を修正しました。入力データのタイムゾーンに合わせて現在時刻を取得および補間するように改善しました。</li><li><code>v.ip()</code> において、無効な入力があった場合のエラーメッセージに元の値を表示するように改善しました。</li></ul><h2 id="_1-2-3-2026-03-15" tabindex="-1">[1.2.3] - 2026-03-15 <a class="header-anchor" href="#_1-2-3-2026-03-15" aria-label="Permalink to &quot;[1.2.3] - 2026-03-15&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>v.str()</code> で文字列の長さを検証する <code>min()</code>, <code>max()</code>, <code>range()</code> メソッドを追加しました。</li><li>クラス記法スキーマ (<code>class Config: ...</code>) を追加し、型アノテーションと <code>Validator</code> クラス属性を既存の dict スキーマ検証経路へ変換できるようになりました。</li><li><code>v.instance(type_cls)</code> / <code>InstanceValidator</code> を追加し、任意クラスに対する <code>isinstance</code> ベースの検証と <code>.coerce()</code> をサポートしました。</li></ul><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>Schema(...)</code> は実行時に dict スキーマだけでなく class 記法スキーマも直接ラップできるようになりました。</li><li>README / <code>docs/index.md</code> / 回帰テストをクラス記法スキーマと Python 3.9+ 型ヒント対応に合わせて更新しました。</li></ul><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>クラス記法スキーマで <code>Optional[T]</code> / <code>Union[T, None]</code> が必須扱いになっていた問題を修正しました。</li><li><code>typing.Union</code> / PEP 604 (<code>T | None</code>) のうち、<code>None</code> 以外の複数メンバーを持つ型がサイレントにパススルーされる問題を修正し、明示的に <code>TypeError</code> を送出するようにしました。</li><li>Python 3.9 で <code>types.UnionType</code> や <code>_UnionType: type | None</code> に起因する import / 実行時エラーが発生しないよう互換性を改善しました。</li><li><code>InstanceValidator.coerce()</code> が元例外を失っていた問題を修正し、例外チェーンを保持するようにしました。</li></ul><h2 id="_1-2-1-2026-03-07" tabindex="-1">[1.2.1] - 2026-03-07 <a class="header-anchor" href="#_1-2-1-2026-03-07" aria-label="Permalink to &quot;[1.2.1] - 2026-03-07&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>v.auto_infer(data, type_map=None, schema_overrides=None)</code> を追加し、既存データから ValidKit スキーマを逆生成できるようになりました。</li><li><code>type_map</code> によるカスタム型対応を追加しました。callable が <code>Validator</code> を返す場合はそのまま使い、プリミティブ値を返す場合は変換後の値で再推論できます。</li><li><code>schema_overrides</code> により、トップレベルの dict フィールドを明示的なバリデータで上書きできるようになりました。</li></ul><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>v.auto_infer()</code> の型ヒントと回帰テストを拡充し、mypy / IDE で扱いやすい API に整理しました。</li><li>ドキュメントとサンプルを <code>auto_infer()</code>・<code>schema_overrides</code>・<code>generate_sample()</code> の現在仕様に合わせて更新しました。</li></ul><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>schema_overrides</code> がネストした dict やリスト要素に漏れて適用される問題を修正しました。</li><li><code>type_map</code> の callable による再推論時に <code>schema_overrides</code> が意図せず伝播する問題を修正しました。</li><li><code>NumberValidator.range()</code> で <code>min &gt; max</code> の不正な境界を定義時に <code>ValueError</code> として拒否し、<code>.min()</code> / <code>.max()</code> との組み合わせでも矛盾を防ぐようにしました。</li><li><code>Schema.generate_sample()</code> が生成候補を各バリデータで再検証するようになり、<code>regex()</code> や <code>custom()</code> を満たせない不正なサンプルを返さず <code>ValueError</code> を送出するようになりました。</li></ul><h2 id="_1-2-0-2026-02-27" tabindex="-1">[1.2.0] - 2026-02-27 <a class="header-anchor" href="#_1-2-0-2026-02-27" aria-label="Permalink to &quot;[1.2.0] - 2026-02-27&quot;">​</a></h2><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>すべてのバリデータに <code>.default(value)</code> を追加しました。欠損キーを自動補完し、設定したフィールドは自動的に optional として扱われます。</li><li>すべてのバリデータに <code>.examples(list)</code> を追加しました。サンプル生成やドキュメント補助に使える例を保持できます。</li><li>すべてのバリデータに <code>.description(text)</code> を追加しました。フィールドの説明文を保持できます。</li><li><code>Schema.generate_sample()</code> を追加しました。スキーマからサンプルデータを再帰的に生成でき、優先順位は <code>.default()</code> → <code>.examples()[0]</code> → 型ごとの代表値です。</li></ul><h3 id="changed-6" tabindex="-1">Changed <a class="header-anchor" href="#changed-6" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>example.py</code> とドキュメントを更新し、新しい補完・サンプル生成 API を反映しました。</li><li>型チェック関連の修正を行い、公開 API の利用時に静的解析しやすくしました。</li></ul><h2 id="_1-1-3-2026-02-27" tabindex="-1">[1.1.3] - 2026-02-27 <a class="header-anchor" href="#_1-1-3-2026-02-27" aria-label="Permalink to &quot;[1.1.3] - 2026-02-27&quot;">​</a></h2><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>各型バリデータの coercion（自動型変換）を実装しました。</li><li>型変換の挙動を検証する専用テストを追加しました。</li><li><code>validkit</code> パッケージ初期化を整備し、主要な関数・クラスをトップレベルから import できるようにしました。</li></ul><h2 id="_1-1-2-2026-02-27" tabindex="-1">[1.1.2] - 2026-02-27 <a class="header-anchor" href="#_1-1-2-2026-02-27" aria-label="Permalink to &quot;[1.1.2] - 2026-02-27&quot;">​</a></h2><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>宣言的なスキーマ定義によるバリデーションライブラリ本体を実装しました。</li><li>カスタムルールを含む基本的な検証機能を追加しました。</li></ul><h2 id="_1-1-1-2026-02-27" tabindex="-1">[1.1.1] - 2026-02-27 <a class="header-anchor" href="#_1-1-1-2026-02-27" aria-label="Permalink to &quot;[1.1.1] - 2026-02-27&quot;">​</a></h2><h3 id="changed-7" tabindex="-1">Changed <a class="header-anchor" href="#changed-7" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>example.py</code> を更新し、利用例を見直しました。</li></ul><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>軽微な不具合を修正しました。</li></ul><h2 id="_1-1-0-2026-02-27" tabindex="-1">[1.1.0] - 2026-02-27 <a class="header-anchor" href="#_1-1-0-2026-02-27" aria-label="Permalink to &quot;[1.1.0] - 2026-02-27&quot;">​</a></h2><h3 id="added-8" tabindex="-1">Added <a class="header-anchor" href="#added-8" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>Schema[T]</code> ジェネリックラッパーを追加し、<code>validate()</code> の戻り値を IDE / 型チェッカーがより正確に推論できるようにしました。</li><li><code>validate()</code> に型補完向けのオーバーロードを追加し、TypedDict と組み合わせた補完体験を改善しました。</li></ul><h3 id="changed-8" tabindex="-1">Changed <a class="header-anchor" href="#changed-8" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>実行時に不要なオーバーロード定義を <code>TYPE_CHECKING</code> 配下へ移し、静的解析向けの実装に整理しました。</li><li><code>1.1.0</code> へバージョンを更新し、<code>Schema[T]</code> を公開 API として位置づけました。</li></ul><h2 id="_1-0-2-2026-01-24" tabindex="-1">[1.0.2] - 2026-01-24 <a class="header-anchor" href="#_1-0-2-2026-01-24" aria-label="Permalink to &quot;[1.0.2] - 2026-01-24&quot;">​</a></h2><h3 id="added-9" tabindex="-1">Added <a class="header-anchor" href="#added-9" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>SECURITY.md</code> を追加し、セキュリティポリシーを整備しました。</li></ul><h3 id="changed-9" tabindex="-1">Changed <a class="header-anchor" href="#changed-9" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>SECURITY.md</code> の日英構成と書式を整理しました。</li><li>ライセンス表記まわりの説明を見直しました。</li></ul><h2 id="_1-0-1-2026-01-24" tabindex="-1">[1.0.1] - 2026-01-24 <a class="header-anchor" href="#_1-0-1-2026-01-24" aria-label="Permalink to &quot;[1.0.1] - 2026-01-24&quot;">​</a></h2><h3 id="added-10" tabindex="-1">Added <a class="header-anchor" href="#added-10" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>MIT ライセンスを追加しました。</li></ul><h3 id="changed-10" tabindex="-1">Changed <a class="header-anchor" href="#changed-10" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>README.md</code> に追加情報とバッジを反映しました。</li></ul><h2 id="_1-0-0-2026-01-24" tabindex="-1">[1.0.0] - 2026-01-24 <a class="header-anchor" href="#_1-0-0-2026-01-24" aria-label="Permalink to &quot;[1.0.0] - 2026-01-24&quot;">​</a></h2><h3 id="added-11" tabindex="-1">Added <a class="header-anchor" href="#added-11" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>CI ワークフローと自動チェック基盤を追加しました。</li><li>パッケージ設定を整備し、最初の公開リリースを作成しました。</li></ul>',79)])])}const b=d(i,[["render",c]]);export{m as __pageData,b as default};
